SELECT personnel_type, MAX(vaccination_rate) AS max_vaccination_rate, created_at, updated_at
FROM personnel_vaccination_rate
GROUP BY personnel_type;

SELECT personnel_type, MAX(vaccination_rate) AS max_vaccination_rate, created_at, updated_at
FROM personnel_vaccination_rate
WHERE personnel_type = 'Employee';

SELECT state 
FROM influenza_vaccination
WHERE vaccination_rate = (SELECT MAX(vaccination_rate) FROM influenza_vaccination);

SELECT personnel_type, SUM(num_vaccinated) AS total_vaccinated
FROM personnel_vaccination
GROUP BY personnel_type;

SELECT vaccination_rate
FROM influenza_vaccination
WHERE county = 'Alameda';

SELECT county, vaccination_rate
FROM influenza_vaccination
ORDER BY vaccination_rate DESC;

SELECT state || ', ' || county AS county_summary
FROM influenza_vaccination
GROUP BY state, county;

SELECT season
FROM influenza_seasons
WHERE id = 1;

SELECT name, personnel_type
FROM personnel
WHERE hospital_id = (SELECT id FROM hospitals WHERE name = 'Hospital A');

SELECT county, vaccination_rate, num_hospitals
FROM influenza_vaccination
ORDER BY vaccination_rate DESC;

SELECT vaccination_rate
FROM influenza_vaccination
ORDER BY vaccination_rate DESC;

SELECT AVG(vaccination_rate) AS avg_vaccination_rate
FROM personnel_vaccination_rate
WHERE personnel_type = 'HCP';

SELECT vaccination_rate
FROM personnel_vaccination_rate
WHERE personnel_type = 'HCP';
